SELECT [Sales Shipment Line].[Document No_], [Sales Shipment Line].[Line No_], Val([Sales Line.Line Discount _]) AS ScontoRIgaTot, Val([Sales Line.Discount _]) AS ScontoRiga, Val([Sales Line.Discount 1 _]) AS ScontoRiga1, Val([Sales Line.Discount 2 _]) AS ScontoRiga2, Val([Sales Line.Discount 3 _]) AS ScontoRiga3, Val([Invoice Discount Value]) AS ScontoFattura, [Sales Shipment Line].Quantity
FROM ([Sales Shipment Line] LEFT JOIN [Sales Line] ON ([Sales Shipment Line].[Order Line No_] = [Sales Line].[Line No_]) AND ([Sales Shipment Line].[Order No_] = [Sales Line].[Document No_])) LEFT JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_
WHERE ((([Sales Shipment Line].Quantity)<>".00000000000000000000") AND (([Sales Shipment Line].No_)=[forms]![principale]![item_control]) AND (([Sales Shipment Line].[constant variable code])=[forms]![principale]![color_control]) AND (([Sales Line].No_)=[forms]![principale]![item_control]) AND (([Sales Line].[constant variable code])=[forms]![principale]![color_control]) AND (([Sales Shipment Line].[Sell-to Customer No_])=[forms]![principale]![filtroclienteean]) AND (([Sales Line].[Sell-to Customer No_])=[forms]![principale]![filtroclienteean]));

